import java.sql.*;

public class SQLInjectionSecure {
    public static void main(String[] args) {
        try {
            // Simulating user input (which should be sanitized/validated)
            String userInput = "'; DROP TABLE users; --";

            Connection conn = DriverManager.getConnection("jdbc:mysql://localhost:3306/database", "username", "password");

            // Use a prepared statement with placeholders (?) for parameters
            String query = "SELECT * FROM users WHERE username = ?";
            PreparedStatement stmt = conn.prepareStatement(query);

            // Set the user input as a parameter to the prepared statement
            stmt.setString(1, userInput);

            ResultSet rs = stmt.executeQuery();

            // Process the query result
            while (rs.next()) {
                System.out.println(rs.getString("username"));
            }

            rs.close();
            stmt.close();
            conn.close();

        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

